mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER ( ORDER BY /* 1순위: 긴급공지 우선 */ CASE WHEN P.TOP_FIX_YN = 'Y' THEN 0 ELSE 1 END ASC,
/* 2순위: 사용자가 클릭한 컬럼 정렬 */
P.ANN_NO
P.TTL
P.WRTR_ID
P.REG_DTTM
P.INQ_CNT
P.REG_DTTM
ASC
DESC
,
/* 3순위: 작성일 최신순 */ P.REG_DTTM DESC,
/* 4순위: 공지번호 최신순 */ P.ANN_NO DESC
) AS ROW_NO , P.ANN_NO , P.BOARD_NO , B.APT_CMPLEX_NO , P.TTL , P.CN , P.WRTR_ID , P.REG_DTTM , P.MDF_DTTM , NVL(P.INQ_CNT, 0) AS INQ_CNT , P.DEL_YN , P.ATCH_FILE_ID , P.TOP_FIX_YN /* * 실제 ATTACH_FILE 테이블에 남아있는 파일 개수 * 왜 필요? * → ATCH_FILE_ID만 보면 파일을 모두 삭제해도 첨부파일 있음으로 보일 수 있음. */ , ( SELECT COUNT(*) FROM ATTACH_FILE F WHERE TO_CHAR(F.FILE_GROUP_NO) = P.ATCH_FILE_ID ) AS FILE_CNT FROM APT_ANN_BOARD_POST P INNER JOIN APT_BOARD_INSTANCE B ON P.BOARD_NO = B.BOARD_NO WHERE P.DEL_YN = 'N' AND B.USE_YN = 'Y' AND B.BOARD_TY_CD = 'NOTICE' AND B.APT_CMPLEX_NO = #{aptCmplexNo} AND P.BOARD_NO = #{boardNo}
AND P.ANN_NO LIKE '%' || #{searchAnnNo} || '%'
AND P.TTL LIKE '%' || #{searchTtl} || '%'
AND P.WRTR_ID LIKE '%' || #{searchWrtrId} || '%'
AND TRUNC(P.REG_DTTM) >= TO_DATE(#{searchStartDt}, 'YYYY-MM-DD')
AND TRUNC(P.REG_DTTM) <= TO_DATE(#{searchEndDt}, 'YYYY-MM-DD')
AND P.TOP_FIX_YN = 'Y'
AND EXISTS ( SELECT 1 FROM ATTACH_FILE F WHERE TO_CHAR(F.FILE_GROUP_NO) = P.ATCH_FILE_ID )
) WHERE ROW_NO BETWEEN #{startRow} AND #{endRow}

mapper.insert:
INSERT INTO APT_ANN_BOARD_POST
(
  ANN_NO
, BOARD_NO
, TTL
, CN
, WRTR_ID
, TOP_FIX_YN
, PBLANC_BGNG_DT
, PBLANC_END_DT
, REG_DTTM
, MDF_DTTM
, INQ_CNT
, DEL_YN
, ATCH_FILE_ID
)
VALUES
    (
      'NTC' || TO_CHAR(SYSDATE, 'YYMMDD') || LPAD(SEQ_ANN_BOARD_POST.NEXTVAL, 4, '0')
    , #{boardNo}
    , #{ttl}
    , #{cn}
    , #{wrtrId}
    , #{topFixYn}

        /* 공고 시작일: 화면에서 값이 오면 그 값, 없으면 오늘 */
    , NVL(TO_DATE(#{pblancBgngDt}, 'YYYY-MM-DD'), TRUNC(SYSDATE))

        /* 공고 종료일: 화면에서 값이 오면 그 값, 없으면 시작일 기준 7일 */
    , NVL(TO_DATE(#{pblancEndDt}, 'YYYY-MM-DD'), TRUNC(SYSDATE) + 7)

        /* 등록일 */
    , SYSDATE

        /* 최초 등록 시 수정일도 등록일과 동일하게 저장 */
    , SYSDATE

    , 0
    , 'N'
    , #{atchFileId}
    )

mapper.update:
UPDATE APT_ANN_BOARD_POST
SET TTL = #{ttl}
  , CN = #{cn}
  , TOP_FIX_YN = #{topFixYn}
  , MDF_DTTM = SYSDATE
WHERE ANN_NO = #{annNo}
  AND BOARD_NO = #{boardNo}
  AND DEL_YN = 'N'

UPDATE APT_ANN_BOARD_POST
SET DEL_YN = 'Y'
  , MDF_DTTM = SYSDATE
WHERE ANN_NO = #{annNo}
  AND BOARD_NO = #{boardNo}
  AND DEL_YN = 'N'

mapper.select:
/* ImngrRegidentNoticeMapper.selectAptCmplexNoByMgmtOfcNo */
SELECT apt_cmplex_no
FROM mgmt_office
WHERE mgmt_ofc_no = #{mgmtOfcNo}
  AND use_yn = 'Y'

/* ImngrRegidentNoticeMapper.selectNoticeBoardNoByAptCmplexNo */
SELECT board_no
FROM apt_board_instance
WHERE apt_cmplex_no = #{aptCmplexNo}
  AND board_ty_cd = 'NOTICE'
  AND use_yn = 'Y'

mapper.insert:
INSERT INTO ATTACH_FILE
(
  FILE_GROUP_NO
, FILE_OG_NAME
, FILE_SAVE_UUID
, FILE_PATH
, FILE_EXT
, FILE_SIZE
, MIME_TYPE
, REG_DT
, FILE_SORT_ORDER
, DOWN_CNT
, GOOGLE_ID
, CAT
)
VALUES
    (
      TO_NUMBER(#{atchFileId})
    , #{fileOgName}
    , #{fileSaveUuid}
    , #{filePath}
    , #{fileExt}
    , #{fileSize}
    , #{mimeType}
    , SYSDATE
    , 1
    , 0
    , #{googleId}
    , 'NOTICE'
    )

mapper.update:
UPDATE APT_ANN_BOARD_POST
SET ATCH_FILE_ID = #{atchFileId}
WHERE ANN_NO = #{annNo}

mapper.select:
/*
 * 첨부파일 그룹에 실제 파일이 몇 개 남았는지 조회
 */
SELECT COUNT(*)
FROM ATTACH_FILE
WHERE TO_CHAR(FILE_GROUP_NO) = #{atchFileId}

mapper.update:
/*
 * 첨부파일을 모두 삭제한 경우 공지사항의 첨부파일 그룹 연결 해제
 */
UPDATE APT_ANN_BOARD_POST
SET ATCH_FILE_ID = NULL
  , MDF_DTTM = SYSDATE
WHERE ANN_NO = #{annNo}
  AND BOARD_NO = #{boardNo}
  AND DEL_YN = 'N'
